FUNCTION ConvolutionForward(input, kernel, bias, stride, padding):
    // input: H x W x C input volume
    // kernel: F x F x C x K (K filters)
    // stride: step size
    // padding: border pixels to add

    // Apply padding to input
    padded_input = ZeroPad(input, padding)

    // Calculate output dimensions
    H_out = floor((H + 2*padding - F) / stride) + 1
    W_out = floor((W + 2*padding - F) / stride) + 1

    // Initialize output volume
    output = Zeros(H_out, W_out, K)

    FOR k IN 0 TO K-1:  // For each filter
        FOR i IN 0 TO H_out-1:  // Output height
            FOR j IN 0 TO W_out-1:  // Output width
                // Calculate correlation
                sum = 0
                FOR ci IN 0 TO C-1:  // Input channels
                    FOR fi IN 0 TO F-1:  // Filter height
                        FOR fj IN 0 TO F-1:  // Filter width
                            h_idx = i*stride + fi
                            w_idx = j*stride + fj
                            sum += padded_input[h_idx][w_idx][ci] * kernel[fi][fj][ci][k]
                output[i][j][k] = sum + bias[k]

    RETURN output

public class ResidualBlock {
    private ConvLayer conv1, conv2;
    private BatchNorm bn1, bn2;
    private int stride;

    public ResidualBlock(int inChannels, int outChannels, int stride) {
        this.stride = stride;

        // First conv layer (may downsample)
        conv1 = new ConvLayer(inChannels, outChannels, 3, stride, 1);
        bn1 = new BatchNorm(outChannels);

        // Second conv layer (same dimensions)
        conv2 = new ConvLayer(outChannels, outChannels, 3, 1, 1);
        bn2 = new BatchNorm(outChannels);
    }

    public Tensor forward(Tensor x) {
        // Store input for skip connection
        Tensor identity = x.clone();

        // Main path: F(x)
        Tensor out = conv1.forward(x);
        out = bn1.forward(out);
        out = ReLU.forward(out);

        out = conv2.forward(out);
        out = bn2.forward(out);

        // Skip connection: x (with projection if dimensions differ)
        if (needsProjection(identity, out)) {
            identity = projectionShortcut(identity);
        }

        // F(x) + x (element-wise addition)
        out = add(out, identity);

        // Final ReLU after addition
        out = ReLU.forward(out);

        return out;
    }

    private boolean needsProjection(Tensor a, Tensor b) {
        return (a.height != b.height) || (a.width != b.width);
    }
}
